<?php\n\nnamespace Database\\Seeders;\n\nuse Illuminate\\Database\\Seeder;\nuse Illuminate\\Support\\Facades\\DB;\nuse App\\Models\\Connect\\Contact;\nuse App\\Models\\Connect\\Domain;\nuse App\\Models\\Connect\\Template;\n\nclass ConnectDatabaseSeeder extends Seeder\n{\n    public function run()\n    {\n        $merchant = DB::table('users')->first();\n        if (!$merchant) {\n            return;\n        }\n\n        Domain::updateOrCreate(\n            ['merchant_id' => $merchant->id, 'domain' => 'originpay.test'],\n            ['status' => 'verified']\n        );\n\n        Contact::updateOrCreate(\n            ['merchant_id' => $merchant->id, 'email' => 'test@originpay.test'],\n            ['name' => 'Test User', 'status' => 'active']\n        );\n\n        Template::updateOrCreate(\n            ['merchant_id' => $merchant->id, 'name' => 'Welcome Email', 'channel' => 'email'],\n            ['subject' => 'Welcome to Origin Connect!', 'status' => 'active']\n        );\n    }\n}\n